/**
 * Custom ESLint rule: max-file-lines.
 *
 * Flags non-test source files exceeding a configurable line
 * threshold (default 300). Long files are a smell — usually a
 * component or hook that's accumulated unrelated concerns and
 * needs decomposition. State machines and other genuinely
 * interlocked code can override per-file with
 * `/* eslint-disable-next-line local/max-file-lines * /` at the
 * top of the file.
 *
 * Exemptions applied automatically:
 *   - `src/generated/` — autogenerated code, varies by API surface
 *   - `*-catalog.ts` / `*-catalog-data.ts` — pure data files
 *   - `*.test.ts` / `*.test.tsx` — tests can be as long as they need
 *
 * Ships as a `warn` by default so adoption can be incremental: the
 * rule surfaces every existing offender as a CI warning, the
 * obvious wins get split over time, and the threshold can be
 * tightened or flipped to `error` once the population is small
 * enough.
 *
 * See `apps/web/docs/CONVENTIONS.md` → "File size".
 */
import path from "node:path";

const DEFAULT_LIMIT = 300;
const EXEMPT_PATH_FRAGMENTS = ["/src/generated/"];
const EXEMPT_NAME_PATTERNS = [
  /-catalog\.ts$/,
  /-catalog-data\.ts$/,
  /\.test\.(ts|tsx)$/,
];

function isExempt(filePath) {
  const posix = filePath.split(path.sep).join("/");
  if (EXEMPT_PATH_FRAGMENTS.some((frag) => posix.includes(frag))) return true;
  const basename = path.basename(filePath);
  return EXEMPT_NAME_PATTERNS.some((re) => re.test(basename));
}

export const maxFileLines = {
  meta: {
    type: "suggestion",
    docs: {
      description:
        "Flag non-test source files exceeding the line threshold (default 300).",
    },
    schema: [
      {
        type: "object",
        properties: {
          limit: { type: "integer", minimum: 1 },
        },
        additionalProperties: false,
      },
    ],
    messages: {
      tooLong:
        "File has {{lines}} lines, exceeds the {{limit}}-line threshold. " +
        "Extract components, hooks, or utilities to keep files focused. " +
        "If genuinely interlocked (e.g. state machine), add " +
        "`/* eslint-disable-next-line local/max-file-lines */` at the top " +
        "with a one-line reason. See CONVENTIONS.md → 'File size'.",
    },
  },
  create(context) {
    const filePath = context.filename ?? context.getFilename();
    if (isExempt(filePath)) return {};
    const limit = context.options?.[0]?.limit ?? DEFAULT_LIMIT;
    return {
      Program(node) {
        const source = context.sourceCode.getText();
        // Count physical lines including the trailing newline if present.
        const lines = source.length === 0 ? 0 : source.split("\n").length;
        if (lines > limit) {
          context.report({
            node,
            messageId: "tooLong",
            data: { lines: String(lines), limit: String(limit) },
          });
        }
      },
    };
  },
};
